// DATA 객체 끝

// ============================================================================
// 상수 정의
// ============================================================================

const ROUTES = {
    '김포공항': ['양촌역', '구래역', '마산역', '장기역', '운양역', '걸포역', '사우역', '풍무역', '고촌역', '김포공항'],
    '양촌역': ['김포공항', '고촌역', '풍무역', '사우역', '걸포역', '운양역', '장기역', '마산역', '구래역', '양촌역']
};

// ============================================================================
// 혼잡도 계산 함수
// ============================================================================

function calcCong(st, dir, day, h, DATA) {
    const TRAIN_CAPACITY = 172; // 정원 (C)
    const route = ROUTES[dir];
    const si = route.indexOf(st); // 현재 역 인덱스
    
    // 요일 타입 ('평일' 또는 '토일')
    const dayType = ['월', '화', '수', '목', '금'].includes(day) ? '평일' : '토일';
    
    // STEP 1: 구간 통과 인원 계산 (P(n))
    let cumulativePassengers = 0; // P(n)
    
    for (let i = 0; i <= si; i++) {
        const s = route[i];
        if (DATA.usage[s] && DATA.usage[s][day] && DATA.usage[s][day][h]) {
            const boarding = DATA.usage[s][day][h]['승차'] || 0;
            const alighting = DATA.usage[s][day][h]['하차'] || 0;
            cumulativePassengers += boarding;
            cumulativePassengers -= alighting;
        }
    }
    cumulativePassengers = Math.max(0, cumulativePassengers);
    
    // STEP 2: 시간당 열차 운행 횟수 (M(t))
    const hourlySchedule = DATA.timetable[st][dir][dayType][h];
    const trainCount = (hourlySchedule && hourlySchedule.length > 0) ? hourlySchedule.length : 1; // M(t)
    
    // STEP 3: 시발열차 수 계산 (동적 계산)
    let originTrains = 0;
    if (si > 0) { // 첫 번째 역이 아닐 경우
        const prevStation = route[si - 1];
        const prevHourlySchedule = DATA.timetable[prevStation][dir][dayType][h];
        const prevTrainCount = (prevHourlySchedule && prevHourlySchedule.length > 0) ? prevHourlySchedule.length : trainCount;
        originTrains = Math.max(0, trainCount - prevTrainCount);
    }
    
    // STEP 4: 열차당 평균 탑승 인원 및 혼잡도 계산
    const avgPassengersPerTrain = cumulativePassengers / trainCount;
    const congestionPercentage = (avgPassengersPerTrain / TRAIN_CAPACITY) * 100;
    
    return {
        total: Math.round(cumulativePassengers),       // P(n)
        avg: Math.round(avgPassengersPerTrain),        // P(n) / M(t)
        pct: Math.round(congestionPercentage),         // ( (P(n) / M(t)) / C ) * 100
        trains: trainCount,                             // M(t)
        originTrains: originTrains                      // 동적으로 계산된 시발열차 수
    };
}

// ============================================================================
// 혼잡도 레벨 계산
// ============================================================================

function getLv(pct) {
    if (pct >= 180) return { n: 10, c: '#ff0000', t: '매우 혼잡', e: '🔴' };
    if (pct >= 150) return { n: 9, c: '#ff4500', t: '상당히 혼잡', e: '🟠' };
    if (pct >= 130) return { n: 8, c: '#ff6347', t: '혼잡', e: '🟠' };
    if (pct >= 100) return { n: 7, c: '#ffa500', t: '다소 혼잡', e: '🟡' };
    if (pct >= 80) return { n: 6, c: '#ffd700', t: '보통', e: '🟡' };
    if (pct >= 60) return { n: 5, c: '#ffff00', t: '여유', e: '🟢' };
    if (pct >= 40) return { n: 4, c: '#adff2f', t: '쾌적', e: '🟢' };
    if (pct >= 20) return { n: 3, c: '#00ff00', t: '매우 쾌적', e: '🟢' };
    if (pct >= 10) return { n: 2, c: '#00fa9a', t: '한산', e: '✅' };
    return { n: 1, c: '#00ffff', t: '매우 한산', e: '✅' };
}

// ============================================================================
// 다음 열차 찾기 함수
// ============================================================================

function findNext(st, dir, day, curH, curM, DATA) {
    const dayType = ['월', '화', '수', '목', '금'].includes(day) ? '평일' : '토일';
    const result = [];
    
    // 현재 시간부터 끝까지 검색
    for (let h = curH; h <= 24; h++) {
        const hStr = String(h).padStart(2, '0');
        const schedule = DATA.timetable[st]?.[dir]?.[dayType]?.[hStr];
        
        if (!schedule || schedule.length === 0) continue;
        
        for (let train of schedule) {
            const trainMinute = train.minute;
            
            // 현재 시간 이후의 열차만
            if (h > curH || (h === curH && trainMinute >= curM)) {
                result.push({ h, m: trainMinute });
                
                // 최대 2개만 (이번 열차 + 다음 열차)
                if (result.length >= 2) {
                    return result;
                }
            }
        }
    }
    
    return result;
}

// ============================================================================
// 구간별 혼잡도 계산 (노선도용)
// ============================================================================

function calcRoute(st, dir, day, h, DATA) {
    const route = ROUTES[dir];
    const si = route.indexOf(st);
    const result = [];
    
    for (let i = si + 1; i < route.length; i++) {
        const cong = calcCong(route[i], dir, day, h, DATA);
        const lv = getLv(cong.pct);
        result.push({
            station: route[i],
            pct: cong.pct,
            color: lv.c,
            level: lv.n,
            text: lv.t,
            emoji: lv.e
        });
    }
    
    return result;
}

// ============================================================================
// Cloudflare Pages Functions Handler
// ============================================================================

export async function onRequestGet(context) {
    const { request } = context;
    const url = new URL(request.url);
    const origin = request.headers.get('Origin') || '';
    
    // OPTIONS 요청 처리 (CORS Preflight)
    if (request.method === 'OPTIONS') {
        return new Response(null, {
            status: 204,
            headers: corsHeaders(origin)
        });
    }
    
    // Domain Lock 검증
    if (!ALLOWED_ORIGINS.includes(origin)) {
        return new Response(JSON.stringify({
            success: false,
            error: 'Access denied. Unauthorized domain.',
            code: 'DOMAIN_NOT_ALLOWED'
        }), {
            status: 403,
            headers: corsHeaders(origin)
        });
    }
    
    // 쿼리 파라미터 파싱
    const station = url.searchParams.get('station');
    const direction = url.searchParams.get('direction');
    const day = url.searchParams.get('day');
    const hour = parseInt(url.searchParams.get('hour') || '0');
    const minute = parseInt(url.searchParams.get('minute') || '0');
    
    // 유효성 검증
    if (!station || !direction || !day) {
        return new Response(JSON.stringify({
            success: false,
            error: 'Missing required parameters: station, direction, day',
            code: 'MISSING_PARAMS'
        }), {
            status: 400,
            headers: corsHeaders(origin)
        });
    }
    
    try {
        // 1. 다음 열차 찾기
        const trains = findNext(station, direction, day, hour, minute, {"timetable":{...DATA.timetable},"usage":{...DATA.usage}});
        
        if (trains.length === 0) {
            return new Response(JSON.stringify({
                success: true,
                data: {
                    trains: [],
                    message: '운행하는 열차가 없습니다.'
                }
            }), {
                status: 200,
                headers: corsHeaders(origin)
            });
        }
        
        // 2. 각 열차에 대한 혼잡도 정보 계산
        const trainInfo = trains.map(train => {
            const hourStr = String(train.h).padStart(2, '0');
            const cong = calcCong(station, direction, day, hourStr, {"timetable":{...DATA.timetable},"usage":{...DATA.usage}});
            const lv = getLv(cong.pct);
            const route = calcRoute(station, direction, day, hourStr, {"timetable":{...DATA.timetable},"usage":{...DATA.usage}});
            
            return {
                time: {
                    hour: train.h,
                    minute: train.m
                },
                congestion: {
                    ...cong,
                    level: lv.n,
                    color: lv.c,
                    text: lv.t,
                    emoji: lv.e
                },
                route: route
            };
        });
        
        // 3. 응답 반환
        return new Response(JSON.stringify({
            success: true,
            data: {
                trains: trainInfo,
                query: {
                    station,
                    direction,
                    day,
                    hour,
                    minute
                }
            },
            timestamp: new Date().toISOString(),
            copyright: '© 2024 REAL KEEPER. All Rights Reserved.'
        }), {
            status: 200,
            headers: corsHeaders(origin)
        });
        
    } catch (error) {
        return new Response(JSON.stringify({
            success: false,
            error: 'Internal server error',
            code: 'SERVER_ERROR',
            message: error.message
        }), {
            status: 500,
            headers: corsHeaders(origin)
        });
    }
}
